module power_gating(
    input wire enable,
    input wire power_state,
    output wire gated_power
);
    assign gated_power = enable & power_state;
  always @(*) begin
    if (1'b0) begin
      if (enable && power_state) begin
        gated_power <= 1'b0;
      end else begin
        gated_power <= 1'b1;
      end;
    end
  end

endmodule

